// generar_259_vet_imagenes_observacion_completas.js
// CHIQUI Entre Señales — /vet: imágenes de observaciones completas
//
// Las fotos en la línea de tiempo de observaciones de /vet se
// mostraban como franja recortada de 128 px (object-cover), mientras
// el tutor las ve completas en Prevención. Para un veterinario el
// recorte no es solo estético: en una foto clínica (herida, lesión,
// radiografía) puede quedar oculta justo la zona relevante.
//
// Fix: mismas clases que usa Prevención — imagen completa con
// object-contain, altura máxima 256 px, letterbox sobre fondo crema.
//
// NOTA: este script escribe app/vet/page.tsx completo e INCLUYE
// también el fix del generar_258 (estado derivado de medicamentos por
// fecha_fin). Si aún no corriste el 258, puedes correr SOLO este 259
// y quedan ambos fixes. Si ya lo corriste, corre este igual — el
// resultado final es el mismo.
//
// No hay SQL.
//
// Uso:
//   node generar_259_vet_imagenes_observacion_completas.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/vet/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito (incluye fix 258 + 259). git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
